import{_ as a,o as s,c as t,ai as i}from"./chunks/framework.CsYGeNYI.js";const m=JSON.parse('{"title":"测试","description":"","frontmatter":{"read_when":["运行或修复测试"],"summary":"如何在本地运行测试（vitest）以及何时使用 force/coverage 模式","title":"测试","x-i18n":{"generated_at":"2026-02-03T10:09:52Z","model":"claude-opus-4-5","provider":"pi","source_hash":"be7b751fb81c8c94b1293624bdca6582e60a26084960d1df9558061969502e6f","source_path":"reference/test.md","workflow":15}},"headers":[],"relativePath":"zh-CN/reference/test.md","filePath":"zh-CN/reference/test.md","lastUpdated":1771906665000}'),o={name:"zh-CN/reference/test.md"};function r(c,e,d,p,n,l){return s(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="测试" tabindex="-1"><a class="header-anchor" href="#测试">#</a> 测试</h1><ul><li><p>完整测试套件（测试集、实时测试、Docker）：<a href="/docs/help/testing">测试</a></p></li><li><p><code>pnpm test:force</code>：终止任何占用默认控制端口的遗留 Gateway 网关进程，然后使用隔离的 Gateway 网关端口运行完整的 Vitest 套件，这样服务器测试不会与正在运行的实例冲突。当之前的 Gateway 网关运行占用了端口 18789 时使用此命令。</p></li><li><p><code>pnpm test:coverage</code>：使用 V8 覆盖率运行 Vitest。全局阈值为 70% 的行/分支/函数/语句覆盖率。覆盖率排除了集成密集型入口点（CLI 连接、gateway/telegram 桥接、webchat 静态服务器），以保持目标集中在可单元测试的逻辑上。</p></li><li><p><code>pnpm test:e2e</code>：运行 Gateway 网关端到端冒烟测试（多实例 WS/HTTP/节点配对）。</p></li><li><p><code>pnpm test:live</code>：运行提供商实时测试（minimax/zai）。需要 API 密钥和 <code>LIVE=1</code>（或提供商特定的 <code>*_LIVE_TEST=1</code>）才能取消跳过。</p></li></ul><h2 id="模型延迟基准测试-本地密钥" tabindex="-1"><a class="header-anchor" href="#模型延迟基准测试-本地密钥">#</a> 模型延迟基准测试（本地密钥）</h2><p>脚本：<a href="https://github.com/NJX-njx/opensoul/blob/main/scripts/bench-model.ts" target="_blank" rel="noreferrer"><code>scripts/bench-model.ts</code></a></p><p>用法：</p><ul><li><code>source ~/.profile &amp;&amp; pnpm tsx scripts/bench-model.ts --runs 10</code></li><li>可选环境变量：<code>MINIMAX_API_KEY</code>、<code>MINIMAX_BASE_URL</code>、<code>MINIMAX_MODEL</code>、<code>ANTHROPIC_API_KEY</code></li><li>默认提示词：&quot;Reply with a single word: ok. No punctuation or extra text.&quot;</li></ul><p>上次运行（2025-12-31，20 次）：</p><ul><li>minimax 中位数 1279ms（最小 1114，最大 2431）</li><li>opus 中位数 2454ms（最小 1224，最大 3170）</li></ul><h2 id="新手引导-e2e-docker" tabindex="-1"><a class="header-anchor" href="#新手引导-e2e-docker">#</a> 新手引导 E2E（Docker）</h2><p>Docker 是可选的；这仅用于容器化的新手引导冒烟测试。</p><p>在干净的 Linux 容器中完整的冷启动流程：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/e2e/onboard-docker.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>此脚本通过伪终端驱动交互式向导，验证配置/工作区/会话文件，然后启动 Gateway 网关并运行 <code>opensoul health</code>。</p><h2 id="qr-导入冒烟测试-docker" tabindex="-1"><a class="header-anchor" href="#qr-导入冒烟测试-docker">#</a> QR 导入冒烟测试（Docker）</h2><p>确保 <code>qrcode-terminal</code> 在 Docker 中的 Node 22+ 下加载：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test:docker:qr</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>',16)])])}const u=a(o,[["render",r]]);export{m as __pageData,u as default};
